/**
 * Composable for account group modal handlers in AccountHub.
 */
import { ref, type Ref } from 'vue';
import { debug } from '@/utils/debug';
import type { AccountGroup } from '@/models/WealthTrackDataModels';

type CreateGroupFn = (name: string) => Promise<AccountGroup | null>;
type UpdateGroupFn = (id: number, name: string) => Promise<AccountGroup | null>;
type DeleteGroupFn = (id: number) => Promise<boolean>;
type SaveMembersFn = (groupId: number, accountIds: number[], existing: number[]) => Promise<boolean>;

export function useAccountGroupHandlers(
  groupMembersMap: Ref<Map<number, number[]>>,
  loadGroups: () => Promise<void>,
  createGroup: CreateGroupFn,
  updateGroup: UpdateGroupFn,
  deleteGroup: DeleteGroupFn,
  saveGroupMembers: SaveMembersFn,
) {
  const accountGroupModalOpen = ref(false);
  const accountGroupModalType = ref<'create' | 'edit'>('create');
  const editingGroupId = ref(0);
  const editingGroupName = ref('');
  const editingGroupMemberIds = ref<number[]>([]);

  const openCreateAccountGroupModal = (): void => {
    accountGroupModalType.value = 'create';
    editingGroupId.value = 0;
    editingGroupName.value = '';
    editingGroupMemberIds.value = [];
    accountGroupModalOpen.value = true;
  };

  const openEditAccountGroupModal = (groupId: number, groupName: string): void => {
    accountGroupModalType.value = 'edit';
    editingGroupId.value = groupId;
    editingGroupName.value = groupName;
    editingGroupMemberIds.value = groupMembersMap.value.get(groupId) || [];
    accountGroupModalOpen.value = true;
  };

  const closeAccountGroupModal = (): void => { accountGroupModalOpen.value = false; };

  const handleAccountGroupSave = async (data: { name: string; accountIds: number[]; groupId?: number }): Promise<void> => {
    try {
      const isEditingExisting = accountGroupModalType.value === 'edit' || !!data.groupId;
      const targetGroupId = data.groupId || editingGroupId.value;
      if (isEditingExisting) {
        const groupUpdated = await updateGroup(targetGroupId, data.name);
        if (!groupUpdated) return;
        const existingMembers = groupMembersMap.value.get(targetGroupId) || [];
        const membersSaved = await saveGroupMembers(targetGroupId, data.accountIds, existingMembers);
        if (!membersSaved) return;
      } else {
        const group = await createGroup(data.name);
        if (!group) return;
        const membersSaved = await saveGroupMembers(group.id, data.accountIds, []);
        if (!membersSaved) return;
      }
      await loadGroups();
      closeAccountGroupModal();
    } catch (error) {
      debug.error('[AccountHub] Save group error:', error);
    }
  };

  const handleDeleteGroup = async (groupId: number): Promise<void> => {
    if (confirm('Are you sure you want to delete this group?')) {
      await deleteGroup(groupId);
      await loadGroups();
    }
  };

  const handleDeleteGroupFromModal = async (groupId: number): Promise<void> => {
    if (confirm('Are you sure you want to delete this group?')) {
      await deleteGroup(groupId);
      await loadGroups();
    }
  };

  return {
    accountGroupModalOpen, accountGroupModalType,
    editingGroupId, editingGroupName, editingGroupMemberIds,
    openCreateAccountGroupModal, openEditAccountGroupModal, closeAccountGroupModal,
    handleAccountGroupSave, handleDeleteGroup, handleDeleteGroupFromModal,
  };
}

import { ref, onMounted } from 'vue';
import { apiService } from '@/services/ApiService';
import type { Account, Institution, AccountUpdateRequest } from '@/models/WealthTrackDataModels';
import type { ReferenceDataItem } from '@/models/ReferenceData';
import { debug } from '@/utils/debug';

export interface AnalyticsEditSavePayload {
  name: string;
  institutionId: number;
  typeId: number;
  statusId: number;
  openedAt?: string;
  closedAt?: string;
  accountNumber?: string;
  sortCode?: string;
  rollRefNumber?: string;
  interestRate?: string;
  fixedBonusRate?: string;
  fixedBonusRateEndDate?: string;
  releaseDate?: string;
  numberOfShares?: string;
  underlying?: string;
  price?: string;
  purchasePrice?: string;
  pensionMonthlyPayment?: string;
  assetClass?: string;
  encumbrance?: string;
}

export function useAnalyticsEdit(onSaved?: () => Promise<void> | void) {
  const editingAccount = ref<Account | null>(null);
  const editModalOpen = ref(false);
  const editModalError = ref<string | null>(null);
  const institutions = ref<Institution[]>([]);
  const accountTypes = ref<ReferenceDataItem[]>([]);
  const accountStatuses = ref<ReferenceDataItem[]>([]);

  onMounted(async () => {
    try {
      const [insts, types, statuses] = await Promise.all([
        apiService.getInstitutions(),
        apiService.getReferenceData('account_type'),
        apiService.getReferenceData('account_status'),
      ]);
      institutions.value = insts;
      accountTypes.value = types;
      accountStatuses.value = statuses;
    } catch (e) {
      debug.error('[useAnalyticsEdit] Failed to load reference data', e);
    }
  });

  async function openEdit(accountId: number): Promise<void> {
    editModalError.value = null;
    try {
      editingAccount.value = await apiService.getAccount(accountId);
      editModalOpen.value = true;
    } catch (e) {
      debug.error('[useAnalyticsEdit] Failed to load account', e);
    }
  }

  async function handleSave(payload: AnalyticsEditSavePayload): Promise<void> {
    if (!editingAccount.value) return;
    editModalError.value = null;
    try {
      const update: AccountUpdateRequest = {
        name: payload.name,
        typeId: payload.typeId,
        statusId: payload.statusId,
        accountNumber: payload.accountNumber,
        sortCode: payload.sortCode,
        rollRefNumber: payload.rollRefNumber,
        interestRate: payload.interestRate,
        fixedBonusRate: payload.fixedBonusRate,
        fixedBonusRateEndDate: payload.fixedBonusRateEndDate,
        releaseDate: payload.releaseDate,
        numberOfShares: payload.numberOfShares,
        underlying: payload.underlying,
        price: payload.price,
        purchasePrice: payload.purchasePrice,
        pensionMonthlyPayment: payload.pensionMonthlyPayment,
        assetClass: payload.assetClass,
        encumbrance: payload.encumbrance,
      };
      await apiService.updateAccount(editingAccount.value.id, update);
      editModalOpen.value = false;
      editingAccount.value = null;
      await onSaved?.();
    } catch (e) {
      editModalError.value = e instanceof Error ? e.message : 'Failed to save account';
    }
  }

  function closeEdit(): void {
    editModalOpen.value = false;
    editingAccount.value = null;
    editModalError.value = null;
  }

  return {
    editingAccount, editModalOpen, editModalError,
    institutions, accountTypes, accountStatuses,
    openEdit, handleSave, closeEdit,
  };
}

/**
 * Handles account balance update and win event actions for the AccountHub.
 */
import type { Ref } from 'vue';
import type { PortfolioItem } from '@/models/WealthTrackDataModels';
import { apiService } from '@/services/ApiService';
import { debug } from '@/utils/debug';

interface PortfolioState {
  items: PortfolioItem[];
  error: string | null;
}

export function useHubEventHandlers(
  state: PortfolioState,
  loadPortfolio: () => Promise<void>,
  currentAccountId: Ref<number>,
  accountType: Ref<string | undefined>,
  openEventsModal: (id: number, name: string, type?: string) => Promise<void>,
) {
  const handleUpdateBalance = async (accountId: number, value: string): Promise<void> => {
    try {
      const grossValue = parseFloat(value);
      if (Number.isNaN(grossValue)) { state.error = 'Invalid balance value'; return; }
      const item = state.items.find(i => i.account.id === accountId);
      const encumbrance = item?.account.encumbrance;
      if (encumbrance) {
        await apiService.updateAccount(accountId, { encumbrance, newGrossBalance: grossValue.toString() });
        await loadPortfolio();
      } else {
        await apiService.createAccountEvent(accountId, { event_type: 'Balance', value: grossValue.toString() });
        if (item) {
          const now = new Date().toISOString();
          item.latestBalance = { id: item.latestBalance?.id ?? 0, accountId, userId: item.latestBalance?.userId ?? 0, eventType: 'Balance', value: grossValue.toString(), createdAt: now, updatedAt: now };
        }
      }
    } catch (error) { state.error = error instanceof Error ? error.message : 'Failed to update balance'; }
  };

  const handleAddWin = async (winAmount: string): Promise<void> => {
    try {
      await apiService.createAccountEvent(currentAccountId.value, { event_type: 'Win', value: winAmount });
      await loadPortfolio();
      const accountName = state.items.find(item => item.account.id === currentAccountId.value)?.account.name || 'Account';
      await openEventsModal(currentAccountId.value, accountName, accountType.value);
    } catch (error) { debug.error('[AccountHub] Failed to add win event:', error); }
  };

  return { handleUpdateBalance, handleAddWin };
}

