/**
 * Composable for managing eligible accounts, tax returns, and documents in a period.
 */
import { ref } from 'vue';
import type { EligibleAccount, TaxDocument, TaxReturnUpsertRequest } from '@models/TaxModels';
import { taxService } from '@services/TaxService';
import { useToast } from '@composables/useToast';

export function useTaxHub() {
  const accounts = ref<EligibleAccount[]>([]);
  const loading = ref(false);
  const error = ref<string | null>(null);
  const { showError } = useToast();

  async function loadAccounts(periodId: number): Promise<void> {
    loading.value = true;
    error.value = null;
    try {
      accounts.value = await taxService.getEligibleAccounts(periodId);
    } catch (err) {
      error.value = err instanceof Error ? err.message : 'Failed to load accounts';
    } finally {
      loading.value = false;
    }
  }

  async function saveReturn(
    periodId: number,
    accountId: number,
    data: TaxReturnUpsertRequest,
  ): Promise<boolean> {
    try {
      const updated = await taxService.upsertReturn(periodId, accountId, data);
      const idx = accounts.value.findIndex((a) => a.accountId === accountId);
      if (idx !== -1) {
        accounts.value[idx] = { ...accounts.value[idx], taxReturn: updated };
      }
      return true;
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Failed to save tax return';
      showError(msg);
      return false;
    }
  }

  async function uploadDocument(
    periodId: number,
    accountId: number,
    file: File,
  ): Promise<TaxDocument | null> {
    try {
      const doc = await taxService.uploadDocument(periodId, accountId, file);
      const idx = accounts.value.findIndex((a) => a.accountId === accountId);
      if (idx !== -1) {
        accounts.value[idx] = {
          ...accounts.value[idx],
          documents: [...accounts.value[idx].documents, doc],
        };
      }
      return doc;
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Failed to upload document';
      showError(msg);
      return null;
    }
  }

  async function downloadDocument(docId: number, filename: string): Promise<void> {
    try {
      const blob = await taxService.downloadDocument(docId);
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      a.click();
      URL.revokeObjectURL(url);
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Failed to download document';
      showError(msg);
    }
  }

  async function deleteDocument(_periodId: number, accountId: number, docId: number): Promise<void> {
    try {
      await taxService.deleteDocument(docId);
      const idx = accounts.value.findIndex((a) => a.accountId === accountId);
      if (idx !== -1) {
        accounts.value[idx] = {
          ...accounts.value[idx],
          documents: accounts.value[idx].documents.filter((d) => d.id !== docId),
        };
      }
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Failed to delete document';
      showError(msg);
    }
  }

  return {
    accounts,
    loading,
    error,
    loadAccounts,
    saveReturn,
    uploadDocument,
    downloadDocument,
    deleteDocument,
  };
}

/**
 * Composable for managing tax periods (list, create, delete, selection).
 */
import { ref } from 'vue';
import type { TaxPeriod, TaxPeriodCreateRequest } from '@models/TaxModels';
import { taxService } from '@services/TaxService';
import { useToast } from '@composables/useToast';

export function useTaxPeriods() {
  const periods = ref<TaxPeriod[]>([]);
  const selectedPeriodId = ref<number | null>(null);
  const loading = ref(false);
  const error = ref<string | null>(null);
  const { showError } = useToast();

  const selectedPeriod = (): TaxPeriod | null =>
    periods.value.find((p) => p.id === selectedPeriodId.value) ?? null;

  async function loadPeriods(): Promise<void> {
    loading.value = true;
    error.value = null;
    try {
      periods.value = await taxService.listPeriods();
      if (periods.value.length > 0 && selectedPeriodId.value === null) {
        selectedPeriodId.value = periods.value[0].id;
      }
    } catch (err) {
      error.value = err instanceof Error ? err.message : 'Failed to load tax periods';
    } finally {
      loading.value = false;
    }
  }

  async function createPeriod(data: TaxPeriodCreateRequest): Promise<TaxPeriod | null> {
    try {
      const created = await taxService.createPeriod(data);
      periods.value = [created, ...periods.value];
      selectedPeriodId.value = created.id;
      return created;
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Failed to create tax period';
      showError(msg);
      return null;
    }
  }

  async function deletePeriod(periodId: number): Promise<void> {
    try {
      await taxService.deletePeriod(periodId);
      periods.value = periods.value.filter((p) => p.id !== periodId);
      if (selectedPeriodId.value === periodId) {
        selectedPeriodId.value = periods.value[0]?.id ?? null;
      }
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Failed to delete tax period';
      showError(msg);
    }
  }

  function selectPeriod(periodId: number): void {
    selectedPeriodId.value = periodId;
  }

  return {
    periods,
    selectedPeriodId,
    selectedPeriod,
    loading,
    error,
    loadPeriods,
    createPeriod,
    deletePeriod,
    selectPeriod,
  };
}

/**
 * Client-side image compression using the Canvas API.
 * Non-image files are returned unchanged.
 */

const MAX_DIMENSION = 1200;
const JPEG_QUALITY = 0.8;

function isImage(file: File): boolean {
  return file.type.startsWith('image/');
}

function loadImage(src: string): Promise<HTMLImageElement> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = reject;
    img.src = src;
  });
}

function scaleDown(width: number, height: number): { width: number; height: number } {
  const max = MAX_DIMENSION;
  if (width <= max && height <= max) return { width, height };
  const ratio = width > height ? max / width : max / height;
  return { width: Math.round(width * ratio), height: Math.round(height * ratio) };
}

export async function compressFile(file: File): Promise<File> {
  if (!isImage(file)) return file;

  const objectUrl = URL.createObjectURL(file);
  try {
    const img = await loadImage(objectUrl);
    const { width, height } = scaleDown(img.naturalWidth, img.naturalHeight);

    const canvas = document.createElement('canvas');
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext('2d');
    if (!ctx) return file;
    ctx.drawImage(img, 0, 0, width, height);

    const outputType = file.type === 'image/png' ? 'image/png' : 'image/jpeg';
    const quality = outputType === 'image/jpeg' ? JPEG_QUALITY : undefined;

    return new Promise<File>((resolve) => {
      canvas.toBlob(
        (blob) => {
          if (!blob) { resolve(file); return; }
          resolve(new File([blob], file.name, { type: outputType }));
        },
        outputType,
        quality,
      );
    });
  } finally {
    URL.revokeObjectURL(objectUrl);
  }
}

